import React from 'react'
import { useNavigate } from 'react-router-dom';

const PrivateRoute = ({isLoggedIn,children}) => {
    const navigate=useNavigate();
    if(isLoggedIn)
    {
        return children;
    }
    else{
        navigate
    }
}

export default PrivateRoute
